### Frontend (React)
First, we need to set up a simple React component to display rooms. Let's call it `RoomList.js`.

```jsx
// RoomList.js
import React from 'react';

const RoomList = ({ rooms }) => {
  return (
    <div>
      <h1>Room List</h1>
      <ul>
        {rooms.map((room) => (
          <li key={room.id}>{room.name}</li>
        ))}
      </ul>
    </div>
  );
};

export default RoomList;
```

### Backend (Express + MongoDB)
Now, let's set up the Express server with MongoDB integration. We'll use Mongoose for database operations.

```javascript
// server.js
const express = require('express');
const mongoose = require('mongoose');
const app = express();
const port = 5000;

// Middleware
app.use(express.json());

// Connect to MongoDB
mongoose.connect('mongodb://localhost:27017/room-manager', {
  useNewUrlParser: true,
  useUnifiedTopology: true,
});

const RoomSchema = new mongoose.Schema({
  name: String,
  capacity: Number,
});

const Room = mongoose.model('Room', RoomSchema);

// Routes
app.get('/api/rooms', async (req, res) => {
  try {
    const rooms = await Room.find();
    res.json(rooms);
  } catch (err) {
    res.status(500).json({ message: err.message });
  }
});

app.post('/api/rooms', async (req, res) => {
  const room = new Room({
    name: req.body.name,
    capacity: req.body.capacity,
  });

  try {
    const newRoom = await room.save();
    res.status(201).json(newRoom);
  } catch (err) {
    res.status(400).json({ message: err.message });
  }
});

// Start the server
app.listen(port, () => {
  console.log(`Server running on http://localhost:${port}`);
});
```

