#include <iostream>
#include <string>
#include <map>

// Define a map to store common mathematical functions and their derivatives
std::map<std::string, std::pair<std::string, std::string>> functions = {
    {"x", {"1", "1"}},  // Derivative of x is 1
    {"sin(x)", {"cos(x)", "cos(x)"}},  // Derivative of sin(x) is cos(x)
    {"cos(x)", {"-sin(x)", "-sin(x)"}},  // Derivative of cos(x) is -sin(x)
    {"exp(x)", {"exp(x)", "exp(x)"}},   // Derivative of exp(x) is exp(x)
    {"ln(x)", {"1/x", "1/x"}},          // Derivative of ln(x) is 1/x
    {"log(x)", {"1/(x * ln(10))", "1/(x * ln(10))"}}  // Derivative of log(x) is 1/(x * ln(10))
};

// Function to parse and compute the derivative of a simple expression
std::string parseDerivative(const std::string& expression) {
    auto it = functions.find(expression);
    if (it != functions.end()) {
        return it->second.first;
    }
    // If the expression is not in the predefined list, we can't handle it here.
    // For more complex expressions, we would need a more sophisticated parser.
    std::cout << "Unsupported function: " << expression << std::endl;
    return "0";  // Default to 0 if unsupported
}

int main() {
    std::string func;
    std::cout << "Enter a mathematical function of x: ";
    std::cin >> func;

    std::string derivative = parseDerivative(func);

    if (!derivative.empty()) {
        std::cout << "The derivative of " << func << " is: " << derivative << std::endl;
    } else {
        std::cout << "Could not compute the derivative." << std::endl;
    }

    return 0;
}
